INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1542, 196110, 5, 1976, '2003', '我叫阿然，2003是我的20大寿。20了，还单身一人，是一种耻辱。两年前，有人跟我说，18岁没有经历过爱情是一种不幸。当时我不以为然，心里默想，那是小女人的心声，只有小女人才会把爱情看得那么重要的吧。我和朋友的理想是以后开一间名叫亚玛逊的咖啡店，弄成单身俱乐部的样子，周末大家在一起聚聚，聊聊音乐，或是电影，等等之类的。但，这是一年前的事了。我们的单身俱乐部，现在已不具规模，那一帮吵着独身主义的女生，而今各有各的主了，一年里甚至没有多少时间见我的面。哎，女人，我只有这样感叹。李碧华姐姐说过，女人之间是不会有真正的友谊的。也许，是真的吧？！
<br>他是一个很帅的男生，初中时，我跟他是一个多学期的前后桌。后来 ，毕业后，我有4年没见过他了，我回过以前的学校，在学校周围转悠过多次， 因为他的家在学校附近，可是，都没有再见过他。我以为我会可以把他放在心里，多年以后说起，可以说，哦，他啊，我以前很喜欢他的。
<br>2003，终于有了一次又见到他的机会。同学会那天，他 去的很晚。从见到他的第一眼，我知道我完了，4年多的美好愿望化为泡影，我一直美好的以为，我喜欢的只是他在我心中的幻影，并不是真正的他，我以为我只要再见他一回，就可以不会再那么喜欢他了。可是！为什么，我现在也开始鄙视我自己为小女人了。居然没脸没皮的打电话给他，聊着一些古老的话题，说一些肉麻的话。女人，真的都是感情动物吗？！
<br>有一个童话的开头是说一个小女孩四岁的时候向天使许了一个愿，希望她在20岁生日的那天遇到她的恋人，留着长发，会弹吉他。听到这个童话，也是在2003，我的20岁，能不能遇到我的恋人呢？', '我叫阿然，2003是我的20大寿。20了，还单身一人，是一种耻辱。两年前，有人跟我说，18岁没有经历过爱情是一种不幸。当时我不以为然，心里默想，那是小女人的心声，只有小女人才会把爱情看得那么重要的吧。我和朋友的理想是以后开一间名叫亚玛逊的咖啡店，弄成单身俱乐部的样子，周末大家在一起聚聚，聊聊音乐，或是电影，等等之类的。但，这是一年前的事了。我们的单身俱乐部，现在已不具规模，那一帮吵着独身主义的女生，而今各有各的主了，一年里甚至没有多少时间见我的面。哎，女人，我只有这样感叹。李碧华姐姐说过，女人之间是不会有真正的友谊的。也许，是真的吧？！

